class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        int res = n;
        for (int i = 0; i < (1 << n); i++) {
            int cnt = 0;
            for (int j = 0; j < n; j++) {
                if ((i >> j) & 1) {
                    cnt++;
                }
            }
            int xor = 0;
            for (int j = 0; j < n; j++) {
                if ((i >> j) & 1) {
                    xor ^= nums[j];
                }
            }
            int cnt_k = 0;
            for (int j = 0; j <= n - k; j++) {
                if ((xor ^ nums[j]) == 0) {
                    cnt_k++;
                }
            }
            res = min(res, n - cnt_k);
        }
        return res;
    }
};
```

